using Microsoft.EntityFrameworkCore;

// EF Core 9 Cosmos DB breaking changes and their fixes.

class CosmosContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=dummy",
            "CatalogDb",
            cosmosOptions =>
            {
                // FIX 2: EF Core 9 blocks synchronous I/O on the Cosmos provider.
                // Existing sync calls (e.g. .ToList(), .First()) will throw
                // InvalidOperationException at runtime.
                // Preferred fix: convert all queries to async (ToListAsync, etc.).
                // Interim workaround if async conversion isn't feasible yet:
                cosmosOptions.AllowSynchronousIO();
            });
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // FIX 1: EF Core 9 changed the default Cosmos discriminator property
        // from "Discriminator" to "$type". Existing documents still store
        // "Discriminator", so reads would silently fail to match.
        // Explicitly keep the old property name for backward compatibility.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
}

